  "cecr-b12-edu-m2": [
    { id: "cecr-b12-edu-m2-contrast-1", type: "mcq", prompt: "« J'apprends le chinois. » — avec objet direct.", promptEn: "«I learn Chinese.» — with direct object.", choices: ["我学汉语。", "我学习汉语。", "Les deux sont acceptables", "我复习汉语。"], correctIndex: 2, explanation: "学 (1 syllabe) et 学习 (2 syllabes) sont très proches. Avec un objet (汉语), les deux marchent : 学汉语 (plus concis) / 学习汉语 (plus formel). 复习 = RÉVISER (ce qu'on a déjà appris).", explanationEn: "学 and 学习 both work with objects. 学 = concise, 学习 = more formal. 复习 = review (what was learned)." },
    { id: "cecr-b12-edu-m2-contrast-2", type: "mcq", prompt: "« Je suis en train d'étudier. » — sans objet.", promptEn: "«I'm studying.» — no object.", choices: ["我在学习。", "我在学。", "我在复习。", "我在考试。"], correctIndex: 0, explanation: "SANS objet, on préfère 学习 (le 学 seul est rarement intransitif). 我在学 sonne incomplet. 我在复习 = « je suis en train de réviser » (possible mais spécifique).", explanationEn: "WITHOUT an object, prefer 学习 (学 alone feels incomplete). 复习 = reviewing (specific)." },
    { id: "cecr-b12-edu-m2-contrast-3", type: "mcq", prompt: "« Je révise pour l'examen. »", promptEn: "«I'm reviewing for the exam.»", choices: ["我复习考试。", "我学习考试。", "我学考试。", "我考试复习。"], correctIndex: 0, explanation: "复习 = réviser (ce qui a déjà été appris). 学/学习 = apprendre (nouveau). On ne dit pas *学考试 car on apprend un sujet, pas un examen.", explanationEn: "复习 = review what's learned. 学/学习 = learn new material. Don't use 学 with 考试 (exam) as object." },
    { id: "cecr-b12-edu-m2-contrast-4", type: "mcq", prompt: "« Cette semaine, je pratique la calligraphie. »", promptEn: "«This week, I'm practicing calligraphy.»", choices: ["这周我练习书法。", "这周我学习书法。", "这周我复习书法。", "这周我考试书法。"], correctIndex: 0, explanation: "练习 = PRATIQUER (exercer une compétence). 学习 = apprendre. 复习 = réviser. Distinction clé : 学 (nouveau) → 练 (pratique) → 复 (révision).", explanationEn: "练习 = practice. 学习 = learn new. 复习 = review. Sequence: 学 → 练 → 复." },
    { id: "cecr-b12-edu-m2-contrast-5", type: "mcq", prompt: "« Il faut mémoriser ces caractères. »", promptEn: "«You have to memorize these characters.»", choices: ["要背这些汉字。", "要学习这些汉字。", "要复习这些汉字。", "要练习这些汉字。"], correctIndex: 0, explanation: "背 = mémoriser par cœur (spécialement pour poèmes, listes, caractères). 学习 = apprendre (compréhension). 复习 = réviser ce qui a déjà été appris. 背 est plus fort et spécifique.", explanationEn: "背 = memorize by heart (specific). 学习 = learn (broad)." },
    { id: "cecr-b12-edu-m2-contrast-6", type: "mcq", prompt: "Séquence logique d'apprentissage :", promptEn: "Logical learning sequence:", choices: ["学习 (apprendre) → 练习 (pratiquer) → 复习 (réviser)", "复习 → 学习 → 练习", "练习 → 复习 → 学习", "Ces verbes sont interchangeables"], correctIndex: 0, explanation: "Séquence pédagogique : 学 (découvrir du nouveau) → 练 (consolider par la pratique) → 复 (revoir pour garder). Cette hiérarchie vous aide à choisir le verbe adéquat.", explanationEn: "Pedagogical sequence: 学 (discover new) → 练 (practice/solidify) → 复 (review/retain)." },
    { id: "cecr-b12-edu-m2-err-1", type: "error-correction", prompt: "Trouve l'erreur.", promptEn: "Find the error.", sentence: "我 | 现在 | 在 | 学。", choices: ["我", "现在", "在", "学"], correctIndex: 3, explanation: "Erreur : 学 seul (sans objet) sonne incomplet. Il faut 学习 : 我现在在学习 (je suis en train d'étudier).", explanationEn: "Error: 学 alone feels incomplete. Use 学习 without an object." },
    { id: "cecr-b12-edu-m2-err-2", type: "error-correction", prompt: "Trouve l'erreur.", promptEn: "Find the error.", sentence: "我 | 学 | 了 | 考试。", choices: ["我", "学", "了", "考试"], correctIndex: 1, explanation: "Erreur sémantique : on ne « apprend » pas un examen, on RÉVISE pour un examen. Correction : 我复习了考试 (j'ai révisé pour l'examen) ou 我准备了考试 (je me suis préparé).", explanationEn: "Semantic error: you don't \"learn\" an exam, you REVIEW for one. Use 复习 or 准备." },
    { id: "cecr-b12-edu-m2-trans-1", type: "mcq", prompt: "Traduis : « J'étudie le chinois depuis un an. »", promptEn: "Translate: «I've been studying Chinese for a year.»", choices: ["我学汉语学了一年了。", "我学习汉语了一年。", "我复习汉语一年。", "我学一年汉语。"], correctIndex: 0, explanation: "Structure de durée avec répétition verbale : S + V + O + V + 了 + durée + 了 = « V depuis X temps (ongoing) ». Forme canonique pour « depuis ». 学了一年 seul dirait « a étudié un an » (sans ongoing).", explanationEn: "Duration + ongoing: S + V + O + V + 了 + time + 了. 学了一年 alone = \"studied for 1 year\" (past, not necessarily ongoing)." },
    { id: "cecr-b12-edu-m2-trans-2", type: "mcq", prompt: "Traduis : « Je n'ai pas encore révisé pour demain. »", promptEn: "Translate: «I haven't reviewed for tomorrow yet.»", choices: ["我还没复习明天的。", "我还不复习明天的。", "我没复习明天的了。", "我不复习明天的。"], correctIndex: 0, explanation: "« Pas encore » = 还没 (sans 了). 复习 + 明天的 (« ce de demain »). 不复习 serait un refus.", explanationEn: "\"Not yet\" = 还没 (no 了). 复习 + 明天的 (what belongs to tomorrow)." },
    { id: "cecr-b12-edu-m2-fill-1", type: "fill", prompt: "Complète : apprendre un nouveau sujet.", promptEn: "Fill: learning a new topic.", sentence: "我想___法语。", sentenceFr: "Je voudrais apprendre le français.", sentenceEn: "I'd like to learn French.", choices: ["学", "复习", "练习", "背"], correctIndex: 0, explanation: "Apprendre une matière (nouveau) = 学 (ou 学习).", explanationEn: "Learning a new subject = 学 (or 学习)." },
    { id: "cecr-b12-edu-m2-fill-2", type: "fill", prompt: "Complète : réviser pour un examen.", promptEn: "Fill: reviewing for an exam.", sentence: "明天有考试，我在___。", sentenceFr: "J'ai un examen demain, je révise.", sentenceEn: "I have an exam tomorrow, I'm reviewing.", choices: ["复习", "学", "练习", "考试"], correctIndex: 0, explanation: "Réviser (ce qui a déjà été appris) = 复习.", explanationEn: "Reviewing = 复习." }
  ],
